'use strict';
/**
 * Created by siggi on 2/29/16.
 */

const path  = require('path');
const Event = require('jibo-typed-events').Event;
const StateMachine = require('../index').default;
const {
    State,
    TimeoutTransition,
    InternalTransition,
    ImmediateTransition
} = require('../index');

let findRoot = require('find-root');


const Events = {
  E1: 'E1',
  E2: 'E2',
};

describe('All', function() {

  it('loadLib', function() {
    let root = findRoot(module.filename);
    let packageStr = path.join(root, 'package.json');
    let p = require(packageStr);
    let appEntry = path.join(root, p.main);
    let lib = require(appEntry);
    expect(lib.default.prototype.constructor.name).to.equal('StateMachine');
  });

  it('Events', function() {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    let bla = 1;
    s2.onEntry = (trans, result) => {
      bla = result;
    };

    s1.addEventTransition(Events.E1, s2);
    expect(sm.initial).to.be.equal(s1);
    expect(sm.current).to.not.be.ok;

    sm.start();
    expect(sm.current).to.be.equal(s1);
    expect(bla).to.be.equal(1);
    sm.emit(Events.E1, 4);
    expect(sm.current).to.be.equal(s2);
    expect(bla).to.be.equal(4);
  });

  it('Typed Events', function() {
    let sm = new StateMachine();
    let event1 = new Event('Event1');

    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');

    s1.addTypedEventTransition(event1, s2);
    s2.onEntry = (trans, data) => {
      expect(data).to.equal(42);
    };

    expect(sm.initial).to.be.equal(s1);
    expect(sm.current).to.not.be.ok;
    sm.start();
    expect(sm.current).to.be.equal(s1);
    event1.emit(42);
    expect(sm.current).to.be.equal(s2);
  });

  it('Timeout', function(done) {
    this.slow(400);
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    s1.addTransition(new TimeoutTransition('t', s2,  100));

    sm.start();
    expect(sm.current).to.be.equal(s1);
    setTimeout(() => {
      expect(sm.current).to.be.equal(s2);
      done();
    }, 150);
  });

  it('Internal transition', function() {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    let bla1 = 1;
    let bla2 = 1;
    s1.addTransition(new InternalTransition('', s2));
    s2.addTransition(new InternalTransition('', s1));
    s1.onEntry = () => {
      bla1 = 2;
      s1.transitionTo(s2);
    };
    s1.onExit = () => {
      bla2 = 2;
    };

    expect(bla1).to.be.equal(1);
    expect(bla2).to.be.equal(1);
    expect(sm.initial).to.be.equal(s1);
    sm.start();
    expect(sm.current).to.be.equal(s2);
    expect(bla2).to.be.equal(2);
    expect(bla2).to.be.equal(2);
    expect(() => s1.transitionTo(s2)).to.throw(Error);
  });


  it('Immediate transition', function() {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    let bla1 = 1;
    s1.addTransition(new ImmediateTransition('', s2));
    s1.onEntry = () => bla1 = 2;

    expect(bla1).to.be.equal(1);
    expect(sm.initial).to.be.equal(s1);
    sm.start();
    expect(sm.current).to.be.equal(s2);
    expect(bla1).to.be.equal(2);
  });

  it('Big sequence of state transitions', function() {
    let sm = new StateMachine();
    let str = '';

    let createState = (num, last) => {
      let s = new State(sm, 's'+num);
      s.onEntry = () => str += s.name;
      if (last) {
        last.addTransition(new ImmediateTransition('', s));
      }
      return s;
    };

    let s0 = createState(0, null);
    let s1 = createState(1, null);
    s0.addEventTransition(Events.E1, s1);
    let s2 = createState(2, s1);
    let s3 = createState(3, s2);

    let s4 = createState(4, null);
    s3.addEventTransition(Events.E2, s4);
    let s5 = createState(5, s4);

    sm.start();
    expect(str).to.be.equal('s0');
    expect(sm.current).to.be.equal(s0);
    sm.emit(Events.E1);
    expect(sm.current).to.be.equal(s3);
    expect(str).to.be.equal('s0s1s2s3');
    sm.emit(Events.E2);
    expect(sm.current).to.be.equal(s5);
    expect(str).to.be.equal('s0s1s2s3s4s5');

// Map transition trace to a state trace
    let stateTrace = sm.getTrace().map( (trans) => trans.getDestinationState());
    expect(stateTrace).to.deep.equal([s0, s1, s2, s3, s4, s5]);
  });

  it('Loop detection', function() {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    let s3 = new State(sm, 's3');
    s1.addTransition(new ImmediateTransition('', s2));
    s2.addTransition(new ImmediateTransition('', s3));
    s3.addTransition(new ImmediateTransition('', s1));

    expect(() => sm.start()).to.throw(Error);
  });

  it('Asynchronous post-exit method', function(testDone) {
    let arr = [];
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    s1.addEventTransition('event', s2);
    s2.addTransition(new ImmediateTransition('', s1));

    s1.onEntry = () => arr.push('s1-entry');
    s1.onExit = () => arr.push('s1-exit');
    s2.onEntry = () => arr.push('s2-entry');
    s2.onExit = () => arr.push('s2-exit');
    s2.postExit = (exitDone) => {
      arr.push('s2-post-exit');
      setTimeout( () => {
        expect(arr).to.deep.equal(
            [ 's1-entry', 's1-exit', 's2-entry', 's2-exit', 's2-post-exit' ]);
        exitDone();
        expect(arr).to.deep.equal(
            [ 's1-entry', 's1-exit', 's2-entry', 's2-exit', 's2-post-exit', 's1-entry' ]);
        testDone();
      }, 10);
    };

    sm.start();
    sm.emit('event');
  });

  it('stop', function(done) {
    this.slow(400);
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    s1.addTransition(new TimeoutTransition('t', s2,  100));
    let s1WasStopped = false;
    let s2WasEntered = false;
    s1.onStop = () => {
      s1WasStopped = true;
    };
    s2.onEntry = () => {
      s2WasEntered = true;
    };

    sm.start();
    sm.stop();
    expect(sm.current).to.be.equal(null);
    setTimeout(() => {
      expect(sm.current).to.be.equal(null);
      expect(s2WasEntered).to.be.equal(false);
      expect(s1WasStopped).to.be.equal(true, 's1 did not have stop called!');
      done();
    }, 150);
  });

  it('stop with event transition', function() {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');
    s1.addEventTransition('event', s2);
    let s2WasEntered = false;
    s2.onEntry = () => {
      s2WasEntered = true;
    };

    sm.start();
    sm.stop();
    sm.emit('event');
    expect(sm.current).to.be.equal(null);
    expect(s2WasEntered).to.be.equal(false);
  });

  it('update', function() {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s1WasUpdated = false;
    s1.onUpdate = () => {
      s1WasUpdated = true;
    };

    sm.start();
    sm.update();
    expect(sm.current).to.be.equal(s1);
    expect(s1WasUpdated).to.be.equal(true, 's1 did not have stop called!');
  });


  it('destroy (events)', function(done) {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');

    let s2Entered = false;
    s2.onEntry = () => {
      s2Entered = true;
    };
    let event2 = new Event('event2');

    s1.addEventTransition('event1', s2);
    s1.addTypedEventTransition(event2, s2);
    expect(sm.listenerCount('event1')).to.equal(1);
    expect(event2.listenerCount()).to.equal(1);

    setTimeout(() => {
      event2.emit();
      sm.emit('event1');
    }, 10);

    sm.start();
    sm.destroy();
    event2.on( () => {
      process.nextTick( () => {
        expect(s2Entered).to.be.equal(false);
        expect(sm.listenerCount('event1')).to.equal(0);
        expect(event2.listenerCount()).to.equal(1); // still one because we subscribed ourselves also
        done();
      });
    });
  });

  it('destroy (internal transition)', function(done) {
    let sm = new StateMachine();
    let s1 = new State(sm, 's1');
    let s2 = new State(sm, 's2');

    let s2Entered = false;
    s2.onEntry = () => {
      s2Entered = true;
    };

    s1.addTransition(new InternalTransition('bla', s2));

    s1.onEntry = () => {
      process.nextTick( () => {
        s1.transitionTo(s2);
        process.nextTick( () => {
          expect(s2Entered).to.be.equal(false);
          done();
        });
      });
    };

    sm.start();
    sm.destroy();
  });
});
